  ('disabled-6f0ba476-moex-00003', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '依司法院大法官解釋，社會秩序維護法曾對從事性交易之行為人，僅處罰 意圖得利之一方，而不處罰支付對價之相對人的規定，違反下列何種基 本權？', '["工作權", "財產權", "平等權", "人身自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00004', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '依現行憲法及相關法律規定，有關參政權之保障，下列敘述何者正確？', '["創制與複決並非參政權", "秘密投票係為選舉權實施之重要原則", "被選舉權之主體並沒有國籍的限制", "選舉權之實施原則為直接選舉，不包括平等選舉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00005', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '關於司法院大法官審理案件法及憲法訴訟法，下列敘述何者正確？', '["依司法院大法官審理案件法，地方自治團體並無聲請釋憲之途徑", "依憲法訴訟法，僅最高法院法官得聲請違憲判決", "依憲法訴訟法，無憲法解釋疑義之聲請判決類型", "依司法院大法官審理案件法，立委現有總額4分之1以上，得為釋憲聲請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00006', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '依憲法訴訟法規定，有關憲法法庭判決宣告法規範定期失效相關之敘述， 下列何者正確？', '["因舊法規尚未失效，故各法院仍應依舊法判決，不得停止訴訟", "判決法規範定期失效者，各法院應依職權裁定停止審理程序", "審理原因案件之法院，原則上不受定期失效期限之拘束", "審理原因案件之法院，除判決主文另有諭知外，應依舊法為判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00007', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '憲法明文規定人民身體之自由應予保障，下列敘述何者錯誤？', '["人民身體自由係人民在小範圍內動靜坐臥的身體移動自由", "用以抵抗國家公權力及他人不合法的限制人民身體移動的自由", "人民身體自由享有充分保障，乃行使其憲法上所保障其他權利之前提", "強制入院治療係對於人民身體自由之限制，應符合憲法第 8 條及第 23 條規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00008', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '依據憲法本文之規定，監察院提出糾正案之對象為何？', '["行政院及其有關部會", "立法院", "司法院", "考試院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00009', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '依憲法法庭判決，關於誹謗罪與言論自由之保障，下列敘述何者錯誤？', '["人民之名譽權與言論自由，應受憲法無分軒輊之保障，國家原則上均應 給予最大限度之保障", "表意人未提供佐證依據之事實性言論，縱內容涉及公共事務，對公益論 辯貢獻度仍不高，該言論所指述者之名譽權應受較高程度之保障", "涉及私德之誹謗言論，與公共利益無關時，表意人之言論自由應完全退 讓於被指述者名譽權與隱私權之保護", "表意人於社群媒體與自媒體上所為誹謗言論，與一般人日常生活中以言 詞所為口耳間傳播之誹謗言論，在事前查證程序之要求上，並無不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00010', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-decd973b', 'sub-disabled-6f0ba476-01', NULL, 'single_choice', '有關憲法保障之隱私權，下列敘述何者錯誤？', '["隱私權保障範圍包括個人生活私密領域免於他人侵擾之權利", "基於人性尊嚴與個人主體性之維護及人格發展之完整，隱私權為不可或 缺之基本權利", "隱私權保障範圍包括個人資料之自主控制權利", "就資訊隱私權而言，保障人民決定是否揭露其個人資料，但不包括對其 個人資料記載錯誤之更正權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:26+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
